    code = request.form.get("code", "").strip()
    pending = PENDING_MFA.get(username)
    if not pending:
        return "No MFA pending.", 400

    if time.time() - pending["created_at"] > MFA_WINDOW_SECONDS:
        PENDING_MFA.pop(username, None)
        MFA_COMPLETE[username] = False
        return "MFA expired", 401

    if not verify_mfa_code(username, code):
        return "Invalid MFA code", 401

    pending["verified"] = True
    MFA_COMPLETE[username] = True
